SELECT count(*) FROM movie_info, title, movie_keyword, info_type, cast_info, keyword, kind_type, role_type WHERE movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND title.kind_id = kind_type.id AND cast_info.role_id = role_type.id;